1	// Shared URL-state helper for list views (artifacts, etc.).
2	// Reads/writes the well-known query params (q, mediaType, groupBy, sort,
3	// filters.*) while preserving any unrelated keys, including ?back=.
4	
5	export type GroupBy = 'folder' | 'prefix' | 'mediaType'
6	
7	const KNOWN_KEYS = new Set(['q', 'mediaType', 'groupBy', 'sort'])
8	const FILTER_PREFIX = 'filter.'
9	
10	export interface ListURLState {
11		q: string
12		mediaType: string | null
13		groupBy: GroupBy
14		sort: string | null
15		filters: Record<string, string>
16	}
17	
18	export const DEFAULT_GROUP_BY: GroupBy = 'folder'
19	
20	function parseGroupBy(raw: string | null): GroupBy {
21		if (raw === 'prefix' || raw === 'mediaType' || raw === 'folder') return raw
22		return DEFAULT_GROUP_BY
23	}
24	
25	export function readState(params: URLSearchParams): ListURLState {
26		const filters: Record<string, string> = {}
27		for (const [k, v] of params.entries()) {
28			if (k.startsWith(FILTER_PREFIX)) filters[k.slice(FILTER_PREFIX.length)] = v
29		}
30		return {
31			q: params.get('q') ?? '',
32			mediaType: params.get('mediaType'),
33			groupBy: parseGroupBy(params.get('groupBy')),
34			sort: params.get('sort'),
35			filters
36		}
37	}
38	
39	// writeState mutates a copy of `params` with the patch applied. Unrelated
40	// keys (including `back`) are preserved. Empty/null values delete the key.
41	export function writeState(
42		params: URLSearchParams,
43		patch: Partial<ListURLState>
44	): URLSearchParams {
45		const next = new URLSearchParams(params)
46	
47		if ('q' in patch) {
48			if (patch.q) next.set('q', patch.q)
49			else next.delete('q')
50		}
51		if ('mediaType' in patch) {
52			if (patch.mediaType) next.set('mediaType', patch.mediaType)
53			else next.delete('mediaType')
54		}
55		if ('groupBy' in patch) {
56			if (patch.groupBy && patch.groupBy !== DEFAULT_GROUP_BY) next.set('groupBy', patch.groupBy)
57			else next.delete('groupBy')
58		}
59		if ('sort' in patch) {
60			if (patch.sort) next.set('sort', patch.sort)
61			else next.delete('sort')
62		}
63		if ('filters' in patch && patch.filters) {
64			// Replace only the filter.* keys; leave everything else intact.
65			for (const k of Array.from(next.keys())) {
66				if (k.startsWith(FILTER_PREFIX)) next.delete(k)
67			}
68			for (const [k, v] of Object.entries(patch.filters)) {
69				if (v) next.set(FILTER_PREFIX + k, v)
70			}
71		}
72	
73		return next
74	}
75	
76	// Build a back-href that captures the current pathname + relevant search.
77	export function backHref(pathname: string, params: URLSearchParams): string {
78		const s = params.toString()
79		return s ? `${pathname}?${s}` : pathname
80	}
81	
82	export { KNOWN_KEYS, FILTER_PREFIX }
