7	export const ARTIFACTS_QUERY = gql`
8		query Artifacts($projectID: ID!, $first: Int, $after: String, $mediaType: String, $search: String) {
9			artifacts(projectID: $projectID, first: $first, after: $after, mediaType: $mediaType, search: $search) {
10				edges {
11					node {
12						id
13						path
14						title
15						mediaType
16						staleness
17					}
18					cursor
19				}
20				pageInfo {
21					hasNextPage
22					endCursor
23				}
24				totalCount
25			}
26		}
27	`
28	
29	export interface ArtifactNode {
30		id: string
31		path: string
32		title: string
33		mediaType: string
34		staleness: string
35	}
36	
37	export interface ArtifactEdge {
38		node: ArtifactNode
39		cursor: string
40	}
41	
42	export interface PageInfo {
43		hasNextPage: boolean
44		endCursor: string | null
45	}
46	
47	export interface ArtifactConnection {
48		edges: ArtifactEdge[]
49		pageInfo: PageInfo
50		totalCount: number
51	}
52	
53	interface ArtifactsResult {
54		artifacts: ArtifactConnection
55	}
56	
57	export const PAGE_SIZE = 50
58	
59	export const load: PageLoad = async ({ params, url, fetch }) => {
60		const state = readState(url.searchParams)
61		const mediaType = state.mediaType
62		const q = state.q
63		const groupBy: GroupBy = state.groupBy
64	
65		const client = createClient(fetch as unknown as typeof globalThis.fetch)
66		const data = await client.request<ArtifactsResult>(ARTIFACTS_QUERY, {
67			projectID: params.projectId,
68			first: PAGE_SIZE,
69			mediaType: mediaType ?? undefined,
70			search: q ? q : undefined
71		})
72		return {
73			nodeId: params.nodeId,
74			projectId: params.projectId,
75			artifacts: data.artifacts,
76			mediaType,
77			q,
78			groupBy
79		}
80	}
