47	async function mockRoutes(page: import('@playwright/test').Page, state: MockState) {
48		await page.route('/graphql', async (route) => {
49			const body = route.request().postDataJSON() as {
50				query: string;
51				variables?: Record<string, string>;
52			};
53			const q = body.query;
54	
55			if (q.includes('NodeInfo')) {
56				await route.fulfill({
57					status: 200,
58					contentType: 'application/json',
59					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
60				});
61				return;
62			}
63			if (q.includes('Projects') && !q.includes('projectID')) {
64				await route.fulfill({
65					status: 200,
66					contentType: 'application/json',
67					body: JSON.stringify({
68						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
69					})
70				});
71				return;
72			}
73			if (q.includes('query Artifacts(') || q.includes('ArtifactsByPath')) {
74				const list = [ARTIFACT_GENERATED, ARTIFACT_PLAIN];
75				const search = body.variables?.search;
76				const filtered = search
77					? list.filter(
78							(a) =>
79								a.title.toLowerCase().includes(String(search).toLowerCase()) ||
80								a.path.toLowerCase().includes(String(search).toLowerCase())
81						)
82					: list;
83				await route.fulfill({
84					status: 200,
85					contentType: 'application/json',
86					body: JSON.stringify({
87						data: {
88							artifacts: {
89								edges: filtered.map((a, i) => ({
90									node: {
91										id: a.id,
92										path: a.path,
93										title: a.title,
94										mediaType: a.mediaType,
95										staleness: a.staleness
96									},
97									cursor: `c${i}`
98								})),
99								pageInfo: { hasNextPage: false, endCursor: null },
100								totalCount: filtered.length
101							}
102						}
103					})
104				});
105				return;
106			}
107			if (q.includes('ArtifactDetail')) {
108				const id = body.variables?.id;
109				const match = [ARTIFACT_GENERATED, ARTIFACT_PLAIN].find((a) => a.id === id);
110				await route.fulfill({
111					status: 200,
112					contentType: 'application/json',
113					body: JSON.stringify({ data: { artifact: match ?? null } })
114				});
115				return;
116			}
117			if (q.includes('RunExists')) {
118				const id = body.variables?.id;
119				await route.fulfill({
120					status: 200,
121					contentType: 'application/json',
122					body: JSON.stringify({
123						data: { run: id === ARTIFACT_GENERATED.generatedBy.runId ? { id } : null }
124					})
125				});
126				return;
127			}
128			if (q.includes('mutation ArtifactRegenerate')) {
129				state.regenerateCalled = true;
130				state.lastArtifactId = body.variables?.artifactId ?? null;
131				await route.fulfill({
132					status: 200,
133					contentType: 'application/json',
134					body: JSON.stringify({
135						data: {
136							artifactRegenerate: { runId: REGENERATE_RUN_ID, status: 'queued' }
137						}
138					})
139				});
140				return;
141			}
142			if (q.includes('Run(') || q.includes('query Run')) {
143				await route.fulfill({
144					status: 200,
145					contentType: 'application/json',
146					body: JSON.stringify({ data: { run: { id: REGENERATE_RUN_ID } } })
147				});
148				return;
149			}
150			await route.continue();
151		});
152	}
153	
154	// Full US-081b workflow: list → filter → open → renderer → provenance →
155	// Regenerate → run id shown → follow run link → navigate back to artifact.
156	test('US-081b end-to-end: list → filter → open → regenerate → run link → back', async ({
157		page
158	}) => {
159		const state: MockState = { regenerateCalled: false, lastArtifactId: null };
160		await mockRoutes(page, state);
161	
162		// 1. List
163		await page.goto(BASE_URL);
164		await expect(page.getByText('Generated Report')).toBeVisible();
165		await expect(page.getByText('Manual Doc')).toBeVisible();
166	
167		// 2. Filter (search) — narrow to the generated artifact via path/title.
168		const search = page.getByPlaceholder(/Search/i).first();
169		await search.fill('Generated');
170		await expect(page.getByText('Generated Report')).toBeVisible();
171	
172		// 3. Open
173		await page.getByText('Generated Report').first().click();
174		await expect(page).toHaveURL(new RegExp(`/artifacts/${ARTIFACT_GENERATED.id}`));
175	
176		// 4. Verify renderer (markdown body shown). The page renders the artifact
177		//    title as <h1> and the markdown body also renders <h1># Generated
178		//    Report</h1>, so we use .first() to disambiguate without weakening the
179		//    visibility assertion.
180		await expect(page.getByRole('heading', { name: 'Generated Report' }).first()).toBeVisible();
181		await expect(page.getByText(/Body text\./)).toBeVisible();
182	
183		// 5. Provenance panel visible.
184		await expect(page.getByTestId('provenance-panel')).toBeVisible();
185	
186		// 6. Click Regenerate.
187		await page.getByTestId('regenerate-button').click();
188	
189		// 7. Verify run id shown + dispatched mutation called.
190		const runLink = page.getByTestId('regenerate-run-link');
191		await expect(runLink).toBeVisible();
192		await expect(runLink).toHaveText(REGENERATE_RUN_ID);
193		expect(state.regenerateCalled).toBe(true);
194		expect(state.lastArtifactId).toBe(ARTIFACT_GENERATED.id);
195	
196		// 8. Follow run link.
197		await runLink.click();
198		await expect(page).toHaveURL(
199			new RegExp(`/runs/${encodeURIComponent(REGENERATE_RUN_ID).replace(/-/g, '\\-')}`)
200		);
201	
202		// 9. Navigate back to artifact.
203		await page.goBack();
204		await expect(page).toHaveURL(new RegExp(`/artifacts/${ARTIFACT_GENERATED.id}`));
205		await expect(page.getByTestId('provenance-panel')).toBeVisible();
206	});
207	
208	// Regenerate button is hidden when generatedBy is absent (AC#2).
209	test('Regenerate button is not shown when generatedBy is absent', async ({ page }) => {
210		const state: MockState = { regenerateCalled: false, lastArtifactId: null };
211		await mockRoutes(page, state);
212	
213		await page.goto(`${BASE_URL}/${ARTIFACT_PLAIN.id}`);
214		await expect(page.getByRole('heading', { name: 'Manual Doc' })).toBeVisible();
215		await expect(page.getByTestId('provenance-panel')).toHaveCount(0);
216		await expect(page.getByTestId('regenerate-button')).toHaveCount(0);
217	});
218	
219	// Mutation error path: server returns a typed error → inline message in the
220	// provenance panel, page does not crash (AC#4).
221	test('Regenerate error renders inline without crashing the page', async ({ page }) => {
222		const state: MockState = { regenerateCalled: false, lastArtifactId: null };
223		await mockRoutes(page, state);
224		// Override only the mutation to return a typed error.
225		await page.route('/graphql', async (route) => {
226			const body = route.request().postDataJSON() as { query: string };
227			if (body.query.includes('mutation ArtifactRegenerate')) {
228				await route.fulfill({
229					status: 200,
230					contentType: 'application/json',
231					body: JSON.stringify({
232						data: null,
233						errors: [
234							{
235								message: 'regeneration backend unavailable',
236								extensions: { code: 'INTERNAL_ERROR' }
237							}
238						]
239					})
240				});
241				return;
242			}
243			await route.fallback();
244		});
245	
246		await page.goto(`${BASE_URL}/${ARTIFACT_GENERATED.id}`);
247		await page.getByTestId('regenerate-button').click();
248		await expect(page.getByTestId('regenerate-error')).toContainText(
249			/regeneration backend unavailable/
250		);
251		// Page is still alive.
252		await expect(page.getByRole('heading', { name: 'Generated Report' }).first()).toBeVisible();
253	});
